def _reflect_point_xy_mm(
    px: float, py: float, ax: float, ay: float, bx: float, by: float
) -> tuple[float, float]:
    """Reflect (px,py) across the infinite line through (ax,ay)-(bx,by)."""
    dx = bx - ax
    dy = by - ay
    denom = dx * dx + dy * dy
    if denom == 0.0:
        # Degenerate axis — reflect through the point a (point reflection).
        return (2 * ax - px, 2 * ay - py)
    vx = px - ax
    vy = py - ay
    t = (vx * dx + vy * dy) / denom
    proj_x = ax + t * dx
    proj_y = ay + t * dy
    return (2 * proj_x - px, 2 * proj_y - py)


def _reflect_vec2_mm(p: Vec2Mm, axis_start: Vec2Mm, axis_end: Vec2Mm) -> Vec2Mm:
    rx, ry = _reflect_point_xy_mm(
        p.x_mm, p.y_mm, axis_start.x_mm, axis_start.y_mm, axis_end.x_mm, axis_end.y_mm
    )
    return Vec2Mm(xMm=rx, yMm=ry)


def _mirror_wall(w: WallElem, axis: Any) -> WallElem:
    """Mirror a wall: reflect each endpoint in its role.

    The wall's parametric direction (start→end) reverses physically, so
    a hosted door at alongT=t lands at the mirror of its original
    location *without* inverting alongT — the rotation of the start→end
    vector handles that automatically.
    """
    new_start = _reflect_vec2_mm(w.start, axis.start_mm, axis.end_mm)
    new_end = _reflect_vec2_mm(w.end, axis.start_mm, axis.end_mm)
    return w.model_copy(update={"start": new_start, "end": new_end})


def _mirror_polygon(
    pts: list[Vec2Mm], axis_start: Vec2Mm, axis_end: Vec2Mm
) -> list[Vec2Mm]:
    """Reflect each vertex and reverse winding so an outer-CCW polygon
    stays outer-CCW after the orientation flip."""
    reflected = [_reflect_vec2_mm(p, axis_start, axis_end) for p in pts]
    reflected.reverse()
    return reflected


def _apply_mirror_elements(els: dict[str, Element], cmd: MirrorElementsCmd) -> None:
    target_ids: set[str] = set(cmd.element_ids)
    if not target_ids:
        return

    walls_being_mirrored: set[str] = {
        tid for tid in target_ids if isinstance(els.get(tid), WallElem)
    }

    if cmd.also_copy:
        # Build the mirrored copies, then atomically attach them. Hosted
        # openings on a mirrored wall are duplicated onto the new wall.
        new_elements: dict[str, Element] = {}
        wall_copy_id_for: dict[str, str] = {}
        for tid in target_ids:
            el = els.get(tid)
            if el is None:
                continue
            mirrored = _mirror_one(el, cmd)
            if mirrored is None:
                continue
            new_eid = new_id()
            new_elements[new_eid] = mirrored.model_copy(update={"id": new_eid})
            if isinstance(el, WallElem):
                wall_copy_id_for[tid] = new_eid

        for orig_wall_id, host_new_id in wall_copy_id_for.items():
            for el in list(els.values()):
                if isinstance(el, (DoorElem, WindowElem)) and el.wall_id == orig_wall_id:
                    copy_id = new_id()
                    new_elements[copy_id] = el.model_copy(
                        update={"id": copy_id, "wall_id": host_new_id}
                    )

        els.update(new_elements)
        return

    # In-place: mutate each element. Mirroring a wall flips its
    # parametric direction; alongT on hosted doors/windows is *not*
    # touched — the reversed start→end vector already places them at
    # the mirrored physical position.
    for tid in target_ids:
        el = els.get(tid)
        if el is None:
            continue
        mirrored = _mirror_one(el, cmd)
        if mirrored is not None:
            els[tid] = mirrored


def _mirror_one(el: Element, cmd: MirrorElementsCmd) -> Element | None:
    axis = cmd.axis
    if isinstance(el, WallElem):
        return _mirror_wall(el, axis)
    if isinstance(el, (DoorElem, WindowElem)):
        # Standalone mirror of an opening alone is a no-op: the opening
        # lives on its host wall, and the host carries the geometry.
        # When the host is also in the mirror set, the host's reversed
        # start→end already places this opening at its mirror position
        # without any alongT change.
        return None
    if isinstance(el, FloorElem):
        return el.model_copy(
            update={"boundary_mm": _mirror_polygon(el.boundary_mm, axis.start_mm, axis.end_mm)}
        )
    if isinstance(el, RoomElem):
        return el.model_copy(
            update={"outline_mm": _mirror_polygon(el.outline_mm, axis.start_mm, axis.end_mm)}
        )
    if isinstance(el, RoofElem):
        return el.model_copy(
            update={"footprint_mm": _mirror_polygon(el.footprint_mm, axis.start_mm, axis.end_mm)}
        )
    # Other element kinds: silently ignored.
    return None


